function stopAR() {
  if (arStream) { arStream.getTracks().forEach(t => t.stop()); arStream = null; }
  if (ghostMode) { ghostMode = false; stopGhostAudio(); }
  document.getElementById('ar-view').classList.remove('on');
  document.getElementById('ar-video').classList.remove('ghost-mode');
  document.getElementById('ar-grain').classList.remove('on');
  document.getElementById('ar-vignette').classList.remove('on');
  document.getElementById('ar-scratches').classList.remove('on');
  document.getElementById('ar-ghost-ov').classList.remove('on');
  document.getElementById('ar-epoch-banner').classList.remove('on');
  document.getElementById('ar-ghost-btn').classList.remove('active');
  document.getElementById('ar-ghost-btn').innerHTML = '<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="12,6 12,12 15,15"/><path d="M2 12h2M20 12h2M12 2v2M12 20v2" stroke-width="1.5" opacity="0.5"/></svg> Mode Histoire';
  document.getElementById('ar-ov').innerHTML = '';
  document.getElementById('nav-ar').classList.remove('active');
  arActive = false;
}

function updateARDistances() {
  const ring = document.getElementById('ar-distance-ring');
  if (!ring) return;
  const nearest = PLACES.reduce((best, p) => {
    const d = calcDist(userLat, userLng, p.lat, p.lng);
    return d < best.d ? { d, p } : best;
  }, { d: Infinity, p: null });
  if (nearest.p) {
    const dTxt = nearest.d < 1000 ? Math.round(nearest.d)+'m' : (nearest.d/1000).toFixed(1)+'km';
    ring.textContent = `📍 Plus proche : ${nearest.p.name} · ${dTxt}`;
  }
}

function navigateToNearest() {
  const nearest = PLACES.reduce((best, p) => {
    const d = calcDist(userLat, userLng, p.lat, p.lng);
    return d < best.d ? { d, p } : best;
  }, { d: Infinity, p: null });
  if (nearest.p) {
    stopAR();
    startNavigation(nearest.p);
  }
}

// ─── RADAR ────────────────────────────────────────────────────────────────
function openRadar() {
  stopAR();
  document.getElementById('radar-view').classList.add('on');
  startGPSWatch();
  setTimeout(drawRadar, 100);
}

function closeRadar() {
  document.getElementById('radar-view').classList.remove('on');
  document.getElementById('radar-info').classList.add('hidden');
  selectedRadarPlace = null;
}

function drawRadar() {
  const canvas = document.getElementById('radar-canvas');
  const wrap = document.getElementById('radar-canvas-wrap');
  const size = Math.min(wrap.clientWidth, wrap.clientHeight - 20);
  canvas.width = size; canvas.height = size;
  const ctx = canvas.getContext('2d');
  const cx = size/2, cy = size/2, r = size/2 - 10;

  // Fond
  const grad = ctx.createRadialGradient(cx,cy,0,cx,cy,r);
  grad.addColorStop(0,'rgba(26,115,232,0.08)');
  grad.addColorStop(0.5,'rgba(26,115,232,0.04)');
  grad.addColorStop(1,'rgba(0,0,0,0)');
  ctx.fillStyle = grad; ctx.beginPath(); ctx.arc(cx,cy,r,0,Math.PI*2); ctx.fill();

  // Cercles concentriques
  [0.33,0.66,1].forEach((f,i) => {
    ctx.beginPath(); ctx.arc(cx,cy,r*f,0,Math.PI*2);
    ctx.strokeStyle = `rgba(26,115,232,${0.15-i*0.03})`; ctx.lineWidth = 1; ctx.stroke();
    const labels = ['200m','500m','1km'];
    ctx.fillStyle = 'rgba(255,255,255,0.25)'; ctx.font = '10px Manrope'; ctx.textAlign = 'center';
    ctx.fillText(labels[i], cx, cy - r*f + 14);
  });

  // Lignes de la boussole
  [0,90,180,270].forEach(a => {
    const rad = a*Math.PI/180;
    ctx.beginPath(); ctx.moveTo(cx,cy);
    ctx.lineTo(cx+Math.sin(rad)*r, cy-Math.cos(rad)*r);
    ctx.strokeStyle = 'rgba(255,255,255,0.08)'; ctx.lineWidth = 1; ctx.stroke();
  });

  // Axes N S E O
  const dirs = [['N',0],['E',90],['S',180],['O',270]];
  dirs.forEach(([l,a]) => {
    const rad = a*Math.PI/180;
    const x = cx + Math.sin(rad)*(r+2), y = cy - Math.cos(rad)*(r+2);
    ctx.fillStyle = a===0 ? '#e74c3c' : 'rgba(255,255,255,0.5)';
    ctx.font = 'bold 11px Manrope'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.fillText(l, x, y);
  });

  // Sweep animé
  const sweep = (Date.now()/3000) % 1 * Math.PI*2;
  const sweepGrad = ctx.createConicalGradient ? null : null;
  ctx.save();
  ctx.translate(cx,cy); ctx.rotate(sweep);
  const sg = ctx.createLinearGradient(0,-r,0,0);
  sg.addColorStop(0,'rgba(26,115,232,0.0)');
  sg.addColorStop(1,'rgba(26,115,232,0.25)');
  ctx.beginPath(); ctx.moveTo(0,0); ctx.arc(0,0,r,-Math.PI/2,-Math.PI/2+0.8,false);
  ctx.fillStyle = 'rgba(26,115,232,0.15)'; ctx.fill();
  ctx.restore();

  // Dot utilisateur au centre
  ctx.beginPath(); ctx.arc(cx,cy,8,0,Math.PI*2);
  ctx.fillStyle = '#0f1923'; ctx.fill();
  ctx.beginPath(); ctx.arc(cx,cy,4,0,Math.PI*2);
  ctx.fillStyle = '#fff'; ctx.fill();

  // Pins des lieux
  const pinsLayer = document.getElementById('radar-pins-layer');
  pinsLayer.innerHTML = '';
  pinsLayer.style.cssText = `position:absolute;inset:0;pointer-events:auto`;
  const maxDist = 1000;

  PLACES.forEach(place => {
    const dist = calcDist(userLat, userLng, place.lat, place.lng);
    if (dist > maxDist * 1.5) return;
    const bearing = getBearing(userLat, userLng, place.lat, place.lng);
    const normDist = Math.min(dist / maxDist, 1);
    const rad = bearing * Math.PI/180;
    const px = cx + Math.sin(rad)*normDist*r;
    const py = cy - Math.cos(rad)*normDist*r;
    const col = CATS[place.cat]?.color || '#1a73e8';
    const dTxt = dist < 1000 ? Math.round(dist)+'m' : (dist/1000).toFixed(1)+'km';
    const wrapper = document.getElementById('radar-canvas-wrap');
    const wRect = wrapper.getBoundingClientRect();

    const pin = document.createElement('div');
    pin.className = 'radar-pin';
    pin.style.cssText = `left:${px}px;top:${py}px;`;
    pin.innerHTML = `
      <div class="radar-pin-dot" style="background:${col};color:${col};border-color:rgba(255,255,255,0.9)"></div>
      <div class="radar-pin-label">${place.name}<br><span class="radar-pin-dist">${dTxt}</span></div>`;
    pin.onclick = () => selectRadarPlace(place, col, dTxt);
    pinsLayer.appendChild(pin);
  });

  if (document.getElementById('radar-view').classList.contains('on')) {
    requestAnimationFrame(drawRadar);
  }
}

function selectRadarPlace(place, col, dTxt) {
  selectedRadarPlace = place;
  const info = document.getElementById('radar-info');
  info.classList.remove('hidden');
  document.getElementById('radar-info-icon').innerHTML = `<div style="width:40px;height:40px;border-radius:50%;background:${col};display:flex;align-items:center;justify-content:center"><span style="font-size:20px">${place.emoji||'🏛️'}</span></div>`;
  document.getElementById('radar-info-name').textContent = place.name;
  document.getElementById('radar-info-dist').textContent = `${dTxt} · ${CATS[place.cat]?.label||'Lieu'}`;
}

function navigateToSelected() {
  if (!selectedRadarPlace) return;
  closeRadar();
  startNavigation(selectedRadarPlace);
}

// ─── NAVIGATION GPS ───────────────────────────────────────────────────────
function startNavigation(place) {
  navDestLat = place.lat; navDestLng = place.lng;
  navActive = true;

  // Afficher overlay nav
  const ov = document.getElementById('nav-overlay');
  ov.classList.add('on');
  document.getElementById('nav-dest-name').textContent = place.name;
  document.getElementById('nav-dest-cat').textContent = CATS[place.cat]?.label || '';
  document.getElementById('nav-dest-img').src = place.bg || '';

  // Switcher sur la carte
  switchSection('tourisme');
  startGPSWatch();

  // Lancer le calcul d'itinéraire
  _computeNavRoute(place);
}

function _computeNavRoute(place) {
  document.getElementById('nav-top-dist').textContent = 'Calcul en cours…';
  navigator.geolocation.getCurrentPosition(pos => {
    userLat = pos.coords.latitude; userLng = pos.coords.longitude;
    fetch(`https://router.project-osrm.org/route/v1/foot/${userLng},${userLat};${place.lng},${place.lat}?overview=full&geometries=geojson`)
      .then(r => r.json())
      .then(data => {
        if (!data.routes?.length) { showToast('Itinéraire introuvable'); return; }
        const route = data.routes[0];
        const coords = route.geometry.coordinates.map(c => [c[1],c[0]]);
        const distTxt = route.distance < 1000 ? Math.round(route.distance)+'m' : (route.distance/1000).toFixed(1)+'km';
        const timeTxt = Math.round(route.duration/60)+' min';

        document.getElementById('nav-top-time').textContent = timeTxt;
        document.getElementById('nav-top-dist').textContent = distTxt + ' · Itinéraire piéton';

        // Ligne bleue animée
        if (navRouteLayer) map.removeLayer(navRouteLayer);
        navRouteLayer = L.polyline(coords, {
          color: '#1a73e8', weight: 6, opacity: 0.9,
          lineCap: 'round', lineJoin: 'round',
          dashArray: null
        }).addTo(map);

        // Marqueur pulsant utilisateur
        if (navUserMarker) map.removeLayer(navUserMarker);
        const userIcon = L.divIcon({
          html: '<div class="nav-user-pulse"></div>',
          className: '', iconSize: [20,20], iconAnchor: [10,10]
        });
        navUserMarker = L.marker([userLat, userLng], { icon: userIcon }).addTo(map);

        // Marqueur destination
        map.eachLayer(l => { if (l._isNavDest) map.removeLayer(l); });
        const col = CATS[place.cat]?.color || '#1a73e8';
        const destIcon = L.divIcon({
          html: `<div style="width:20px;height:20px;border-radius:50%;background:${col};border:3px solid #fff;box-shadow:0 2px 10px ${col}88"></div>`,
          className: '', iconSize: [20,20], iconAnchor: [10,10]
        });
        const dm = L.marker([place.lat, place.lng], { icon: destIcon }).addTo(map);
        dm._isNavDest = true;

        map.fitBounds(navRouteLayer.getBounds(), { padding: [80,80] });
      });
  }, () => showToast('GPS indisponible'), { enableHighAccuracy: true, timeout: 8000 });
}

function updateNavigation() {
  if (!navActive || !navDestLat) return;
  const dist = calcDist(userLat, userLng, navDestLat, navDestLng);
  const dTxt = dist < 1000 ? Math.round(dist)+'m' : (dist/1000).toFixed(1)+'km';
  document.getElementById('nav-top-dist').textContent = dTxt + ' restants';
  if (navUserMarker) navUserMarker.setLatLng([userLat, userLng]);
  if (dist < 30) {
    showToast('🎉 Vous êtes arrivé !');
    stopNavigation();
  }
}

function stopNavigation() {
  navActive = false;
  document.getElementById('nav-overlay').classList.remove('on');
  if (navRouteLayer) { map.removeLayer(navRouteLayer); navRouteLayer = null; }
  if (navUserMarker) { map.removeLayer(navUserMarker); navUserMarker = null; }
  map.eachLayer(l => { if (l._isNavDest) map.removeLayer(l); });
}

function renderARPins() {
  if (!arActive) return;
  const ov = document.getElementById('ar-ov');
  ov.innerHTML = '';
  const W = window.innerWidth, H = window.innerHeight;
  const fov = 60;
  PLACES.forEach(place => {
    const dist = calcDist(userLat, userLng, place.lat, place.lng);
    if (dist > 2000) return;
    const bearing = getBearing(userLat, userLng, place.lat, place.lng);
    let dAngle = bearing - arHeading;
    while (dAngle > 180) dAngle -= 360;
    while (dAngle < -180) dAngle += 360;
    if (Math.abs(dAngle) > fov / 2 + 10) return;
    const x = W/2 + (dAngle / (fov/2)) * (W/2);
    const y = H * 0.45;
    const col = CATS[place.cat]?.color || '#1a73e8';
    const distTxt = dist < 1000 ? Math.round(dist)+'m' : (dist/1000).toFixed(1)+'km';
    const el = document.createElement('div');
    el.className = 'arc';
    el.style.cssText = `left:${x}px;top:${y}px;--cc:${col}`;
    el.innerHTML = `
      <div class="arc-pin">
        <div class="arc-bubble">
          <div class="arc-icon"><span style="font-size:14px">${place.emoji}</span></div>
          <div class="arc-info">
            <div class="arc-name">${place.name}</div>
            <div class="arc-dist">${distTxt}</div>
          </div>
        </div>
        <div class="arc-stem"></div>
        <div class="arc-dot"></div>
      </div>`;
    el.onclick = () => openImmersive(place.id);
    ov.appendChild(el);
  });
  setTimeout(renderARPins, 1000);
}
function getBearing(lat1,lng1,lat2,lng2) {
  const dLng = (lng2-lng1)*Math.PI/180;
  const y = Math.sin(dLng)*Math.cos(lat2*Math.PI/180);
  const x = Math.cos(lat1*Math.PI/180)*Math.sin(lat2*Math.PI/180)-Math.sin(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.cos(dLng);
  return (Math.atan2(y,x)*180/Math.PI+360)%360;
}
if (window.DeviceOrientationEvent) {
  window.addEventListener('deviceorientation', e => {
    if (e.alpha !== null) { arHeading = e.alpha; document.getElementById('ar-heading-text').textContent = Math.round(e.alpha)+'° · AR Live'; }
  });
}

// ─── ROUTE ────────────────────────────────────────────────────────────────
function startRoute(lat, lng) {
  if (routeLayer) { map.removeLayer(routeLayer); routeLayer = null; }
  map.eachLayer(l => { if (l._isRouteMarker) map.removeLayer(l); });
  document.getElementById('route-banner')?.remove();
  showToast('📍 Calcul de l\'itinéraire…');
  if (!navigator.geolocation) { showToast('GPS non disponible'); return; }
  navigator.geolocation.getCurrentPosition(pos => {
    userLat = pos.coords.latitude; userLng = pos.coords.longitude;
    _computeRoute(parseFloat(lat), parseFloat(lng));
  }, () => _computeRoute(parseFloat(lat), parseFloat(lng)), { enableHighAccuracy: true, timeout: 8000 });
}
function _computeRoute(dLat, dLng) {
  fetch(`https://router.project-osrm.org/route/v1/foot/${userLng},${userLat};${dLng},${dLat}?overview=full&geometries=geojson`)
    .then(r => r.json())
    .then(data => {
      if (!data.routes?.length) { showToast('Itinéraire introuvable'); return; }
      const route = data.routes[0];
      const coords = route.geometry.coordinates.map(c => [c[1],c[0]]);
      const distTxt = route.distance < 1000 ? Math.round(route.distance)+'m' : (route.distance/1000).toFixed(1)+'km';
      const timeTxt = route.duration < 60 ? Math.round(route.duration)+'s' : Math.round(route.duration/60)+' min';
      routeLayer = L.polyline(coords, { color:'#1a73e8', weight:5, opacity:.85, lineCap:'round', lineJoin:'round' }).addTo(map);
      const si = L.divIcon({ html:'<div style="width:14px;height:14px;border-radius:50%;background:#fff;border:3px solid #0f1923;box-shadow:0 2px 8px rgba(26,115,232,.5)"></div>', className:'', iconSize:[14,14], iconAnchor:[7,7] });
      L.marker([userLat,userLng],{icon:si}).addTo(map)._isRouteMarker=true;
      const ei = L.divIcon({ html:'<div style="width:16px;height:16px;border-radius:50%;background:#0f1923;border:3px solid #fff;box-shadow:0 2px 8px rgba(26,115,232,.6)"></div>', className:'', iconSize:[16,16], iconAnchor:[8,8] });
      L.marker([dLat,dLng],{icon:ei}).addTo(map)._isRouteMarker=true;
      map.fitBounds(routeLayer.getBounds(),{padding:[60,60]});
      routeActive = true;
      const banner = document.createElement('div');
      banner.id = 'route-banner';
      banner.innerHTML = `
        <div style="display:flex;align-items:center;gap:12px;">
          <div style="width:36px;height:36px;border-radius:50%;background:#f0f0f0;display:flex;align-items:center;justify-content:center;">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="#0f1923"><path d="M21 3L3 10.53v.98l6.84 2.65L12.48 21h.98L21 3z"/></svg>
          </div>
          <div>
            <div style="font-family:'Manrope';font-weight:800;font-size:14px;color:#0f1923;">${timeTxt} à pied</div>
            <div style="font-family:'Manrope';font-size:11px;color:#9aa0a6;">${distTxt} · Itinéraire piéton</div>
          </div>
        </div>
        <button onclick="cancelRoute()" style="background:none;border:none;font-family:'Manrope';font-weight:700;font-size:12px;color:#ea4335;cursor:pointer;padding:6px 10px;">✕ Annuler</button>`;
      document.getElementById('content').appendChild(banner);
      showToast('✅ Itinéraire calculé');
    })
    .catch(() => showToast('Erreur réseau'));
}
function cancelRoute() {
  if (routeLayer) { map.removeLayer(routeLayer); routeLayer = null; }
  map.eachLayer(l => { if (l._isRouteMarker) map.removeLayer(l); });
  document.getElementById('route-banner')?.remove();
  routeActive = false;
}

// ─── GPS ──────────────────────────────────────────────────────────────────
function locateUser() {
  if (!navigator.geolocation) { showToast('GPS non disponible'); return; }
  navigator.geolocation.getCurrentPosition(pos => {
    userLat = pos.coords.latitude; userLng = pos.coords.longitude;
    map.setView([userLat, userLng], 16);
    if (userMarker) map.removeLayer(userMarker);
    userMarker = L.marker([userLat,userLng],{icon:makeUserMarkerIcon()}).addTo(map);
    showToast('📍 Position trouvée');
  }, () => showToast('GPS refusé'));
}
function makeUserMarkerIcon() {
  return L.divIcon({
    html:`<div style="display:flex;flex-direction:column;align-items:center;">
      <div style="position:relative;display:flex;align-items:center;justify-content:center;width:44px;height:44px;">
        <div class="yah-ring"></div>
        <div class="yah-dot"></div>
      </div>
      <div class="yah-label">Vous êtes ici</div>
    </div>`,
    className:'', iconSize:[80,62], iconAnchor:[40,22],
  });
}

// ─── TOAST ────────────────────────────────────────────────────────────────
let tT;
function showToast(msg) {
  const t = document.getElementById('toast');
  t.textContent = msg; t.classList.add('show');
  clearTimeout(tT); tT = setTimeout(() => t.classList.remove('show'), 2500);
}

// ─── INIT ─────────────────────────────────────────────────────────────────
